public int active()
{
    int ret = next active();

    FormDataSource          purchAgreementHeaderDS      = this.formRun().dataSource(formDataSourceStr(PurchAgreement, PurchAgreementHeader));
    PurchAgreementHeader    purchAgreementHeader        = purchAgreementHeaderDS.cursor();
    ETGCanadaParameters    parameters  = ETGCanadaParameters::find();
    FormRun             formRun     = this.formRun();

    if(ETGACFParameters::find().EnableAbruptTerminationAgreement == NoYes::Yes)
    {
        FormControl             buttoncontrol               = this.formRun().design().controlName(formControlStr(PurchAgreement,ButtonReleaseOrderCreate));
        FormControl             buttoncontrolconfirmation   = this.formRun().design().controlName(formControlStr(PurchAgreement,PurchAgreementProFormaConfirm));

        if(purchAgreementHeader.AgreementState == AgreementState::ETGTerminated || purchAgreementHeader.AgreementState == AgreementState::ETGForceClosed)
        {
            buttoncontrol.enabled(false);
            buttoncontrolconfirmation.enabled(false);
        }
    }

    if(ETGACFParameters::find().EnableContractFDAutomation == NoYes::Yes)
    {
        if(purchAgreementHeader.ETG_IsThirdParty == NoYes::Yes)
        {
            purchAgreementHeaderDS.object(fieldNum(PurchAgreementHeader, DefaultDimension)).allowEdit(false);
        }
        else
        {
            purchAgreementHeaderDS.object(fieldNum(PurchAgreementHeader, DefaultDimension)).allowEdit(true);
        }
    }

    //DMS Integration
    purchAgreementHeaderDS.object(fieldNum(PurchAgreementHeader, ETGDMSDealNumbers)).allowEdit(false);
    //DMS Integration

    //fields to be non-editable integrated from deal
    if (parameters.DMSFieldFreezeDeal && purchAgreementHeader.ETGDMSDealNumbers)
    {
        formRun.design().controlName(formControlStr(PurchAgreement, LineViewHeader_Currency)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, LineViewHeader_ExpirationDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, LineViewHeader_EffectiveDate)).allowEdit(false);

        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_AgreementLineQuantityCommitment_CommitedQuantity)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_AgreementLineQuantityCommitment_ProductUnitOfMeasure)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_AgreementLineQuantityCommitment_PricePerUnit)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_ExpirationDate)).allowEdit(false);

        formRun.design().controlName(formControlStr(PurchAgreement, ValidityPeriodLine_ExpirationDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, ValidityPeriodLine_EffectiveDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, PriceDisc_PricePerUnit)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, ALine_AgreementLineQuantityCommitment_CommitedQuantity)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, ALine_AgreementLineQuantityCommitment_ProductUnitOfMeasure)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, TabFinancialDimensions)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, TabLineDimension)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, TradingDetailsLine)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_Currency1)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, DefaultAgreementLineExpirationDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, DefaultAgreementLineEffectiveDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_VendAccount1)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, Through)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, BrokerageCommissionType)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, BrokerageCommissionValue)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, ReferenceGroup)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, TabHeaderTerm)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, TabHeaderFinancialDimensions)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, ETGCanadaDetails)).allowEdit(false);

    }
    else
    {

        formRun.design().controlName(formControlStr(PurchAgreement, LineViewHeader_Currency)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, LineViewHeader_ExpirationDate)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, LineViewHeader_EffectiveDate)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_AgreementLineQuantityCommitment_CommitedQuantity)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_AgreementLineQuantityCommitment_ProductUnitOfMeasure)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_AgreementLineQuantityCommitment_PricePerUnit)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, AgreementLine_ExpirationDate)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, ValidityPeriodLine_EffectiveDate)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, ValidityPeriodLine_ExpirationDate)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, PriceDisc_PricePerUnit)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, ALine_AgreementLineQuantityCommitment_CommitedQuantity)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, ALine_AgreementLineQuantityCommitment_ProductUnitOfMeasure)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, TabFinancialDimensions)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, TabLineDimension)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, TradingDetailsLine)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_Currency1)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, DefaultAgreementLineExpirationDate)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, DefaultAgreementLineEffectiveDate)).allowEdit(false);
        formRun.design().controlName(formControlStr(PurchAgreement, PurchAgreementHeader_VendAccount1)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, Through)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, BrokerageCommissionType)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, BrokerageCommissionValue)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, ReferenceGroup)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, TabHeaderTerm)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, TabHeaderFinancialDimensions)).allowEdit(true);
        formRun.design().controlName(formControlStr(PurchAgreement, ETGCanadaDetails)).allowEdit(true);

    }

    return ret;
}
